// ---------- Theme (matches v7_dashboard.jsx) ----------
const T = {
  bg: '#0F172A', panel: '#1E293B', panelLight: '#334155',
  text: '#F1F5F9', textDim: '#94A3B8', accent: '#22D3EE',
  blue: '#60A5FA', green: '#34D399', red: '#F87171',
  yellow: '#FBBF24', purple: '#A78BFA', orange: '#FB923C',
  border: '#334155', grid: '#475569',
};
const FONT_MONO = 'Consolas, "SF Mono", Menlo, monospace';
const FONT_SANS = 'Inter, "Segoe UI", system-ui, sans-serif';
const tooltipStyle = {
  contentStyle: { background: T.panel, border: `1px solid ${T.border}`,
                  borderRadius: 4, fontFamily: FONT_MONO, fontSize: 12 },
  itemStyle: { color: T.text }, labelStyle: { color: T.textDim },
};

// Distinct color palette for cohort overlays — picked for max contrast
const COHORT_COLORS = ['#22D3EE', '#34D399', '#FBBF24', '#F87171', '#A78BFA',
                        '#60A5FA', '#FB923C', '#F472B6', '#10B981', '#EAB308',
                        '#EF4444', '#8B5CF6', '#3B82F6', '#F59E0B', '#EC4899',
                        '#06B6D4', '#84CC16', '#F97316', '#D946EF', '#0EA5E9',
                        '#14B8A6', '#FACC15'];

// Distinct colors per age bucket for the Age Ramps view
const AGE_BUCKET_COLORS = { young: '#22D3EE', seasoned: '#FBBF24', aged: '#A78BFA' };

const Panel = ({ title, subtitle, children, style }) => (
  <div style={{ background: T.panel, border: `1px solid ${T.border}`, borderRadius: 8,
                padding: 16, marginBottom: 16, ...style }}>
    {title && <div style={{ color: T.text, fontSize: 14, fontWeight: 600, marginBottom: 4 }}>{title}</div>}
    {subtitle && <div style={{ color: T.textDim, fontSize: 11, marginBottom: 12, fontFamily: FONT_MONO }}>{subtitle}</div>}
    {children}
  </div>
);

const Stat = ({ label, value, hint, color }) => (
  <div style={{ flex: 1, padding: '12px 14px', background: T.panelLight, borderRadius: 6 }}>
    <div style={{ color: T.textDim, fontSize: 11, fontFamily: FONT_MONO, textTransform: 'uppercase' }}>{label}</div>
    <div style={{ color: color || T.text, fontSize: 22, fontWeight: 600, fontFamily: FONT_MONO, marginTop: 2 }}>{value}</div>
    {hint && <div style={{ color: T.textDim, fontSize: 10, marginTop: 2 }}>{hint}</div>}
  </div>
);


// ============================================================================
// Cohort S-curves tab — the headline visualization for V8
// ============================================================================
function TabCohortSCurves({ md }) {
  const cohorts = md.cohort_definitions || [];
  const grids = md.cohort_curve_grids || {};
  const [view, setView] = useState('grid');     // 'grid' or 'overlay'
  const [yAxis, setYAxis] = useState('cpr');    // 'cpr' or 'smm'

  // For each primary cohort: combine its empirical scatter with the smooth fitted curve
  const cohortData = useMemo(() =>
    cohorts.map((c, i) => {
      const grid = grids[c.cohort_id] || [];
      // Merge scatter + grid into a single dataset for ComposedChart
      // We'll plot scatter as Scatter and the grid as Line on top
      return {
        cohort: c,
        color: COHORT_COLORS[i % COHORT_COLORS.length],
        scatter: (c.scatter || []).map(s => ({
          x: s.bin_mid_bp,
          y: yAxis === 'cpr' ? s.actual_cpr : s.actual_smm * 100,
          n: s.n,
        })),
        gridLine: grid.map(p => ({
          x: p.net_bp,
          y: yAxis === 'cpr' ? p.pred_cpr : p.pred_smm * 100,
        })),
      };
    }),
  [cohorts, grids, yAxis]);

  const yLabel = yAxis === 'cpr' ? 'CPR %' : 'SMM × 100';

  if (!cohorts.length) {
    return <Panel title="Cohort S-curves">
      <div style={{ color: T.textDim, fontSize: 12 }}>
        No cohort_definitions in artifact. Run <span style={{fontFamily: FONT_MONO}}>python3 train_v8.py</span>.
      </div>
    </Panel>;
  }

  return (
    <div>
      <Panel
        title="Cohort S-curves: fitted sigmoid vs empirical scatter"
        subtitle="Each panel = one cohort. Dots = mean actual_SMM/CPR per net_refi_bps bin (size ∝ n_loans). Line = fitted 4-param sigmoid. Compare shapes, midpoints, asymptotes across cohorts."
      >
        <div style={{ display: 'flex', gap: 8, marginBottom: 12, alignItems: 'center' }}>
          <span style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11 }}>view:</span>
          {[['grid', 'Small multiples'], ['overlay', 'All cohorts overlay']].map(([k, lab]) => (
            <button key={k} onClick={() => setView(k)} style={{
              background: view === k ? T.accent : T.panelLight,
              color: view === k ? T.bg : T.text,
              border: 'none', borderRadius: 4, padding: '4px 12px',
              fontFamily: FONT_MONO, fontSize: 11, cursor: 'pointer',
            }}>{lab}</button>
          ))}
          <span style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11, marginLeft: 16 }}>y-axis:</span>
          {[['cpr', 'CPR %'], ['smm', 'SMM']].map(([k, lab]) => (
            <button key={k} onClick={() => setYAxis(k)} style={{
              background: yAxis === k ? T.accent : T.panelLight,
              color: yAxis === k ? T.bg : T.text,
              border: 'none', borderRadius: 4, padding: '4px 12px',
              fontFamily: FONT_MONO, fontSize: 11, cursor: 'pointer',
            }}>{lab}</button>
          ))}
          <span style={{ color: T.textDim, marginLeft: 'auto', fontSize: 11 }}>
            {cohorts.length} primary cohorts
          </span>
        </div>

        {view === 'grid' ? (
          <div style={{ display: 'grid',
                        gridTemplateColumns: 'repeat(auto-fit, minmax(360px, 1fr))',
                        gap: 12 }}>
            {cohortData.map(({ cohort, color, scatter, gridLine }) => (
              <div key={cohort.cohort_id}
                   style={{ background: T.panelLight, padding: 8, borderRadius: 6 }}>
                <div style={{ color: T.text, fontSize: 12, fontWeight: 600,
                              marginBottom: 2, fontFamily: FONT_MONO }}>
                  {cohort.cohort_id}
                </div>
                <div style={{ color: T.textDim, fontSize: 10,
                              fontFamily: FONT_MONO, marginBottom: 4 }}>
                  n={(cohort.n || 0).toLocaleString()} · events={cohort.n_events} ·{' '}
                  fit=<span style={{ color: cohort.fit_quality === 'good' ? T.green : T.yellow }}>
                    {cohort.fit_quality}
                  </span> · σ_resid={(cohort.residual_std || 0).toFixed(4)}
                </div>
                <ResponsiveContainer width="100%" height={200}>
                  <ComposedChart margin={{ top: 4, right: 12, bottom: 4, left: 0 }}>
                    <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
                    <XAxis dataKey="x" type="number" stroke={T.textDim}
                           tick={{ fontFamily: FONT_MONO, fontSize: 10 }}
                           domain={[-500, 500]}
                           label={{ value: 'net_refi_bps', position: 'insideBottom',
                                    fill: T.textDim, fontSize: 9, offset: -2 }} />
                    <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 10 }}
                           domain={[0, 'auto']} />
                    <Tooltip {...tooltipStyle}
                             formatter={(v, n, p) =>
                               n === 'y' || n === 'fitted'
                                 ? [`${v.toFixed(2)}`, n === 'fitted' ? 'fitted' :
                                                       `actual (n=${p.payload.n})`]
                                 : [v, n]} />
                    <ReferenceLine x={0} stroke={T.textDim} strokeDasharray="2 2" />
                    <Scatter name="actual" dataKey="y" data={scatter} fill={color}
                             shape="circle" />
                    <Line name="fitted" type="monotone" dataKey="y" data={gridLine}
                          stroke={color} strokeWidth={2} dot={false} />
                  </ComposedChart>
                </ResponsiveContainer>
                <div style={{ color: T.textDim, fontSize: 9,
                              fontFamily: FONT_MONO, marginTop: 4 }}>
                  floor={(cohort.params?.floor || 0).toFixed(4)} ·
                  asymp={(cohort.params?.asymp || 0).toFixed(4)} ·
                  mid={(cohort.params?.mid || 0).toFixed(0)}bp ·
                  slope={(cohort.params?.slope || 0).toFixed(0)}bp
                </div>
              </div>
            ))}
          </div>
        ) : (
          // Overlay view: every cohort's fitted curve on a single chart
          <div>
            <ResponsiveContainer width="100%" height={520}>
              <LineChart margin={{ top: 16, right: 16, bottom: 16, left: 8 }}>
                <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
                <XAxis dataKey="x" type="number" stroke={T.textDim}
                       tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                       domain={[-500, 500]}
                       label={{ value: 'net_refi_bps  (penalty-adjusted)',
                                position: 'insideBottom', fill: T.textDim,
                                fontSize: 11, offset: -8 }} />
                <YAxis stroke={T.textDim}
                       tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                       domain={[0, 'auto']}
                       label={{ value: yLabel, angle: -90,
                                position: 'insideLeft', fill: T.textDim,
                                fontSize: 11 }} />
                <Tooltip {...tooltipStyle} />
                <ReferenceLine x={0} stroke={T.textDim} strokeDasharray="2 2" />
                {cohortData.map(({ cohort, color, gridLine }) => (
                  <Line key={cohort.cohort_id}
                        name={cohort.cohort_id}
                        type="monotone" dataKey="y" data={gridLine}
                        stroke={color} strokeWidth={2} dot={false} />
                ))}
              </LineChart>
            </ResponsiveContainer>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginTop: 8 }}>
              {cohortData.map(({ cohort, color }) => (
                <div key={cohort.cohort_id} style={{ display: 'flex',
                                                       alignItems: 'center', gap: 4,
                                                       fontFamily: FONT_MONO, fontSize: 11,
                                                       color: T.textDim }}>
                  <span style={{ width: 16, height: 3, background: color,
                                 display: 'inline-block' }} />
                  {cohort.cohort_id}
                </div>
              ))}
            </div>
          </div>
        )}
      </Panel>
    </div>
  );
}


// ============================================================================
// Cohort Browser — drill into a single cohort
// ============================================================================
function TabCohortBrowser({ md }) {
  const cohorts = md.cohort_definitions || [];
  const grids = md.cohort_curve_grids || {};
  const [pickIdx, setPickIdx] = useState(0);
  if (!cohorts.length)
    return <Panel title="Cohort Browser"><div style={{color: T.textDim}}>No cohorts.</div></Panel>;
  const c = cohorts[pickIdx];
  const grid = grids[c.cohort_id] || [];
  const merged = (c.scatter || []).map(s => ({
    bin_mid: s.bin_mid_bp, actual_cpr: s.actual_cpr, n: s.n,
  }));

  return (
    <Panel title="Cohort Browser" subtitle="Drill into a single cohort's S-curve fit + diagnostics">
      <select value={pickIdx} onChange={e => setPickIdx(parseInt(e.target.value))}
              style={{ background: T.panel, color: T.text, border: `1px solid ${T.border}`,
                       padding: 6, fontFamily: FONT_MONO, fontSize: 11,
                       borderRadius: 4, width: '100%', marginBottom: 12 }}>
        {cohorts.map((c, i) => (
          <option key={i} value={i}>
            {c.cohort_id} · n={c.n.toLocaleString()} · events={c.n_events} · fit={c.fit_quality}
          </option>
        ))}
      </select>

      <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 16 }}>
        <Stat label="program" value={c.axes?.program} />
        <Stat label="purpose" value={c.axes?.purpose} />
        <Stat label="size"    value={c.axes?.size} />
        <Stat label="n loans" value={(c.n || 0).toLocaleString()} />
        <Stat label="n events" value={c.n_events} />
        <Stat label="fit quality" value={c.fit_quality}
              color={c.fit_quality === 'good' ? T.green : T.yellow} />
      </div>

      <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 16 }}>
        <Stat label="floor" value={(c.params?.floor || 0).toFixed(5)}
              hint="SMM at deep-OTM" />
        <Stat label="asymp" value={(c.params?.asymp || 0).toFixed(5)}
              hint={`SMM ceiling (CPR ≈ ${((1 - Math.pow(1 - (c.params?.asymp || 0), 12)) * 100).toFixed(1)}%)`} />
        <Stat label="mid" value={(c.params?.mid || 0).toFixed(0) + ' bp'}
              hint="Sigmoid inflection" />
        <Stat label="slope" value={(c.params?.slope || 0).toFixed(0) + ' bp'}
              hint="Sharper = lower" />
        <Stat label="residual σ" value={(c.residual_std || 0).toFixed(4)}
              hint="Bin-level fit error" />
      </div>

      <ResponsiveContainer width="100%" height={400}>
        <ComposedChart margin={{ top: 16, right: 16, bottom: 16, left: 0 }}>
          <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
          <XAxis dataKey="x" type="number" stroke={T.textDim}
                 tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                 domain={[-500, 500]}
                 label={{ value: 'net_refi_bps', position: 'insideBottom',
                          fill: T.textDim, fontSize: 11, offset: -8 }} />
          <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                 domain={[0, 'auto']}
                 label={{ value: 'CPR %', angle: -90, position: 'insideLeft',
                          fill: T.textDim, fontSize: 11 }} />
          <Tooltip {...tooltipStyle} />
          <ReferenceLine x={0} stroke={T.textDim} strokeDasharray="2 2" />
          <Scatter name="actual_cpr (per bin)" dataKey="y"
                   data={merged.map(m => ({ x: m.bin_mid, y: m.actual_cpr, n: m.n }))}
                   fill={T.accent} />
          <Line name="fitted_cpr" type="monotone" dataKey="y"
                data={grid.map(g => ({ x: g.net_bp, y: g.pred_cpr }))}
                stroke={T.green} strokeWidth={2.5} dot={false} />
        </ComposedChart>
      </ResponsiveContainer>
    </Panel>
  );
}


// ============================================================================
// Overview tab
// ============================================================================
function TabOverview({ md }) {
  const m = md.metadata || {};
  const cmp = md.comparison_to_v7 || {};
  return (
    <div>
      <Panel title="V8 at a glance"
             subtitle={`Cohort-based S-curve model · ${m.n_cohorts_fit || '?'} primary cohorts · flavor=${m.flavor || 'v8b'}`}>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <Stat label="Test AUC" value={(m.test_auc || 0).toFixed(4)}
                hint={cmp.available ?
                      `vs V7 ${(cmp.v7_test_auc || 0).toFixed(4)}  (Δ${cmp.auc_delta >= 0 ? '+' : ''}${(cmp.auc_delta || 0).toFixed(4)})`
                      : ''}
                color={T.accent} />
          <Stat label="Test log loss" value={(m.test_log_loss || 0).toFixed(5)}
                hint={cmp.available ? `vs V7 ${(cmp.v7_log_loss || 0).toFixed(5)}` : ''} />
          <Stat label="Panel actual CPR" value={(m.panel_actual_cpr || 0).toFixed(2) + '%'} />
          <Stat label="Max pred CPR" value={(m.max_cpr_full_panel || 0).toFixed(2) + '%'}
                hint={`n>90%=${m.n_above_90_cpr || 0}; n>75%=${m.n_above_75_cpr || 0}`}
                color={(m.max_cpr_full_panel || 0) < 90 ? T.green : T.red} />
          <Stat label="# cohorts fit" value={m.n_cohorts_fit || 0}
                hint={`+${m.n_fallback_levels || 0} fallback levels`} />
        </div>
      </Panel>

      <Panel title="V8 architecture vs V7"
             subtitle="Cohort sigmoid lookup replaces V7's globally-shared M_rate × M_program × M_size">
        <div style={{ color: T.textDim, fontSize: 12, fontFamily: FONT_MONO, lineHeight: 1.6 }}>
          <strong style={{color: T.text}}>V8a (pure cohort):</strong> pred_SMM = MIN(cohort_sigmoid(net_refi_bps), smm_cap)
          <br />
          <strong style={{color: T.text}}>V8b (hybrid, default):</strong> pred_SMM = MIN(cohort_sigmoid(net_refi_bps) × M_age × M_maturity × M_lockout × M_burnout, smm_cap)
          <br /><br />
          <strong style={{color: T.text}}>Cohort = program × purpose × size</strong> (5 × 2 × 3 = up to 30 primary cells, sparse cells fall back to coarser cohorts).
          <br />
          M_program / M_size / M_penalty from V7 are absorbed INTO the cohort definition (not multiplied on top).
          M_age / M_maturity / M_lockout / M_burnout are reused from V7 (cohort-invariant in both models).
        </div>
      </Panel>
    </div>
  );
}


